{
  "name": "FreshCheck: Expiry Date Detector",
  "description": "Scan or upload product labels to automatically detect and track expiry dates using Gemini Vision AI.",
  "requestFramePermissions": [
    "camera"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface ExpiryAnalysis {
  productName: string;
  expiryDate: string; // ISO format or clear string
  foundText: string;
  confidence: 'high' | 'medium' | 'low';
  isExpired: boolean;
  daysRemaining: number | null;
  status: 'expired' | 'expiring-soon' | 'valid' | 'unknown';
}

export type ScanMode = 'camera' | 'upload';

export interface ScanResult extends ExpiryAnalysis {
  id: string;
  timestamp: number;
  imageUrl: string;
}

import { GoogleGenAI, Type } from "@google/genai";
import { ExpiryAnalysis } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const analyzeExpiryImage = async (base64Image: string): Promise<ExpiryAnalysis> => {
  const model = ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: [
      {
        parts: [
          {
            text: `Analyze this image of a product label. 
            1. Find the product name if visible.
            2. Identify the expiry date (EXP, BEST BEFORE, USE BY).
            3. Return the data in valid JSON format.
            4. If multiple dates are found, choose the one clearly marked as expiry.
            5. Today's date is ${new Date().toISOString().split('T')[0]}.`
          },
          {
            inlineData: {
              mimeType: "image/jpeg",
              data: base64Image
            }
          }
        ]
      }
    ],
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          productName: { type: Type.STRING },
          expiryDate: { type: Type.STRING, description: "Expiry date in YYYY-MM-DD format if possible, otherwise as found text" },
          foundText: { type: Type.STRING, description: "The exact text found on the label related to expiry" },
          confidence: { type: Type.STRING, enum: ["high", "medium", "low"] }
        },
        required: ["productName", "expiryDate", "foundText", "confidence"]
      }
    }
  });

  const response = await model;
  const rawJson = response.text || "{}";
  const data = JSON.parse(rawJson);

  // Calculate status logic
  let isExpired = false;
  let daysRemaining: number | null = null;
  let status: ExpiryAnalysis['status'] = 'unknown';

  try {
    const exp = new Date(data.expiryDate);
    if (!isNaN(exp.getTime())) {
      const today = new Date();
      today.setHours(0, 0, 0, 0);
      const diffTime = exp.getTime() - today.getTime();
      daysRemaining = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

      isExpired = daysRemaining < 0;
      if (isExpired) status = 'expired';
      else if (daysRemaining <= 7) status = 'expiring-soon';
      else status = 'valid';
    }
  } catch (e) {
    console.error("Date parsing error", e);
  }

  return {
    ...data,
    isExpired,
    daysRemaining,
    status
  };
};

import React, { useRef, useEffect, useState, useCallback } from 'react';

interface CameraScannerProps {
  onCapture: (base64: string) => void;
  isProcessing: boolean;
}

const CameraScanner: React.FC<CameraScannerProps> = ({ onCapture, isProcessing }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [stream, setStream] = useState<MediaStream | null>(null);
  const [error, setError] = useState<string | null>(null);

  const startCamera = async () => {
    try {
      const mediaStream = await navigator.mediaDevices.getUserMedia({
        video: { facingMode: 'environment' },
        audio: false
      });
      setStream(mediaStream);
      if (videoRef.current) {
        videoRef.current.srcObject = mediaStream;
      }
      setError(null);
    } catch (err) {
      setError("Unable to access camera. Please check permissions.");
      console.error(err);
    }
  };

  const stopCamera = useCallback(() => {
    if (stream) {
      stream.getTracks().forEach(track => track.stop());
      setStream(null);
    }
  }, [stream]);

  useEffect(() => {
    startCamera();
    return () => stopCamera();
  }, []);

  const captureFrame = () => {
    if (videoRef.current && canvasRef.current) {
      const video = videoRef.current;
      const canvas = canvasRef.current;
      canvas.width = video.videoWidth;
      canvas.height = video.videoHeight;
      const ctx = canvas.getContext('2d');
      if (ctx) {
        ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
        const dataUrl = canvas.toDataURL('image/jpeg', 0.8);
        const base64 = dataUrl.split(',')[1];
        onCapture(base64);
      }
    }
  };

  return (
    <div className="relative w-full max-w-md mx-auto aspect-[3/4] bg-black rounded-3xl overflow-hidden shadow-2xl border-4 border-slate-200">
      {error ? (
        <div className="flex flex-col items-center justify-center h-full text-white p-6 text-center">
          <i className="fas fa-exclamation-triangle text-4xl mb-4 text-amber-400"></i>
          <p>{error}</p>
          <button 
            onClick={startCamera}
            className="mt-4 px-6 py-2 bg-indigo-600 hover:bg-indigo-700 rounded-full transition"
          >
            Retry Camera
          </button>
        </div>
      ) : (
        <>
          <video 
            ref={videoRef} 
            autoPlay 
            playsInline 
            className="w-full h-full object-cover"
          />

          {/* Scanning Overlay UI */}
          <div className="absolute inset-0 pointer-events-none flex flex-col items-center justify-center">
            <div className="w-64 h-64 border-2 border-white/50 rounded-2xl relative">
              <div className="absolute top-0 left-0 w-8 h-8 border-t-4 border-l-4 border-indigo-500 -mt-1 -ml-1 rounded-tl-lg"></div>
              <div className="absolute top-0 right-0 w-8 h-8 border-t-4 border-r-4 border-indigo-500 -mt-1 -mr-1 rounded-tr-lg"></div>
              <div className="absolute bottom-0 left-0 w-8 h-8 border-b-4 border-l-4 border-indigo-500 -mb-1 -ml-1 rounded-bl-lg"></div>
              <div className="absolute bottom-0 right-0 w-8 h-8 border-b-4 border-r-4 border-indigo-500 -mb-1 -mr-1 rounded-br-lg"></div>

              {/* Scan Line Animation */}
              {!isProcessing && (
                <div className="absolute top-0 left-0 w-full h-1 bg-indigo-500/50 shadow-[0_0_15px_rgba(99,102,241,0.8)] animate-[scan_2s_linear_infinite]"></div>
              )}
            </div>
            <p className="mt-6 text-white text-sm font-medium bg-black/40 px-4 py-1 rounded-full backdrop-blur-sm">
              Align expiry date within the box
            </p>
          </div>

          <div className="absolute bottom-8 left-0 right-0 flex justify-center px-4">
            <button
              onClick={captureFrame}
              disabled={isProcessing}
              className={`group relative flex items-center justify-center w-20 h-20 bg-white rounded-full shadow-lg transition-all active:scale-95 ${isProcessing ? 'opacity-50 cursor-not-allowed' : 'hover:scale-105'}`}
            >
              <div className="w-16 h-16 border-4 border-slate-100 rounded-full flex items-center justify-center group-hover:border-indigo-100 transition-colors">
                <div className={`w-12 h-12 bg-indigo-600 rounded-full flex items-center justify-center text-white ${isProcessing ? 'animate-pulse' : ''}`}>
                  <i className={`fas ${isProcessing ? 'fa-spinner fa-spin' : 'fa-camera'} text-xl`}></i>
                </div>
              </div>
            </button>
          </div>
        </>
      )}
      <canvas ref={canvasRef} className="hidden" />

      <style>{`
        @keyframes scan {
          0% { transform: translateY(0); }
          100% { transform: translateY(256px); }
        }
      `}</style>
    </div>
  );
};

export default CameraScanner;

import React, { useRef, useState } from 'react';

interface ImageUploaderProps {
  onUpload: (base64: string) => void;
  isProcessing: boolean;
}

const ImageUploader: React.FC<ImageUploaderProps> = ({ onUpload, isProcessing }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [dragActive, setDragActive] = useState(false);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      processFile(file);
    }
  };

  const processFile = (file: File) => {
    const reader = new FileReader();
    reader.onload = () => {
      const base64 = (reader.result as string).split(',')[1];
      onUpload(base64);
    };
    reader.readAsDataURL(file);
  };

  const handleDrag = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (e.type === "dragenter" || e.type === "dragover") {
      setDragActive(true);
    } else if (e.type === "dragleave") {
      setDragActive(false);
    }
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setDragActive(false);
    if (e.dataTransfer.files && e.dataTransfer.files[0]) {
      processFile(e.dataTransfer.files[0]);
    }
  };

  return (
    <div className="w-full max-w-md mx-auto">
      <div 
        className={`relative flex flex-col items-center justify-center w-full aspect-[3/4] border-4 border-dashed rounded-3xl transition-all ${
          dragActive ? 'border-indigo-500 bg-indigo-50' : 'border-slate-200 bg-white hover:border-indigo-300'
        } ${isProcessing ? 'opacity-70 pointer-events-none' : 'cursor-pointer'}`}
        onDragEnter={handleDrag}
        onDragLeave={handleDrag}
        onDragOver={handleDrag}
        onDrop={handleDrop}
        onClick={() => fileInputRef.current?.click()}
      >
        <input 
          ref={fileInputRef}
          type="file" 
          accept="image/*" 
          className="hidden" 
          onChange={handleFileChange}
        />

        <div className="flex flex-col items-center text-slate-500 p-8 text-center">
          <div className={`w-20 h-20 mb-6 rounded-full flex items-center justify-center text-white text-3xl transition-all ${isProcessing ? 'bg-indigo-400 animate-pulse' : 'bg-indigo-600'}`}>
            <i className={`fas ${isProcessing ? 'fa-spinner fa-spin' : 'fa-cloud-upload-alt'}`}></i>
          </div>
          <h3 className="text-xl font-semibold text-slate-800 mb-2">
            {isProcessing ? 'Analyzing Label...' : 'Upload Image'}
          </h3>
          <p className="text-sm leading-relaxed max-w-xs">
            {isProcessing 
              ? 'Our AI is searching for expiry dates and product info...' 
              : 'Drag and drop an image of your product label or click to browse files'}
          </p>
        </div>

        {isProcessing && (
          <div className="absolute inset-0 flex items-center justify-center bg-white/20 backdrop-blur-[2px] rounded-3xl">
             {/* Progress overlay if needed */}
          </div>
        )}
      </div>

      <div className="mt-6 p-4 bg-amber-50 border border-amber-200 rounded-xl flex items-start space-x-3">
        <i className="fas fa-lightbulb text-amber-500 mt-1"></i>
        <p className="text-xs text-amber-800 leading-normal">
          <strong>Tip:</strong> Ensure the expiry date is clearly visible and well-lit for the most accurate results.
        </p>
      </div>
    </div>
  );
};

export default ImageUploader;

import React from 'react';
import { ScanResult } from '../types';

interface ExpiryCardProps {
  item: ScanResult;
  onDelete: (id: string) => void;
}

const ExpiryCard: React.FC<ExpiryCardProps> = ({ item, onDelete }) => {
  const getStatusConfig = () => {
    switch (item.status) {
      case 'expired':
        return {
          bg: 'bg-red-50',
          border: 'border-red-200',
          text: 'text-red-700',
          icon: 'fa-skull-crossbones',
          label: 'Expired',
          pill: 'bg-red-100 text-red-700'
        };
      case 'expiring-soon':
        return {
          bg: 'bg-amber-50',
          border: 'border-amber-200',
          text: 'text-amber-700',
          icon: 'fa-hourglass-half',
          label: 'Expiring Soon',
          pill: 'bg-amber-100 text-amber-700'
        };
      case 'valid':
        return {
          bg: 'bg-emerald-50',
          border: 'border-emerald-200',
          text: 'text-emerald-700',
          icon: 'fa-check-circle',
          label: 'Safe to Consume',
          pill: 'bg-emerald-100 text-emerald-700'
        };
      default:
        return {
          bg: 'bg-slate-50',
          border: 'border-slate-200',
          text: 'text-slate-700',
          icon: 'fa-question-circle',
          label: 'Unknown',
          pill: 'bg-slate-100 text-slate-700'
        };
    }
  };

  const config = getStatusConfig();
  const formattedDate = new Date(item.expiryDate).toLocaleDateString('en-US', {
    month: 'long', day: 'numeric', year: 'numeric'
  });

  return (
    <div className={`relative flex flex-col md:flex-row bg-white rounded-2xl overflow-hidden shadow-sm border ${config.border} transition-all hover:shadow-md mb-4`}>
      <div className="w-full md:w-32 h-32 bg-slate-100 overflow-hidden shrink-0">
        <img src={item.imageUrl} alt={item.productName} className="w-full h-full object-cover" />
      </div>

      <div className="flex-1 p-4 md:p-5">
        <div className="flex justify-between items-start mb-1">
          <h3 className="font-bold text-slate-900 text-lg truncate pr-8">{item.productName || "Unknown Product"}</h3>
          <button 
            onClick={() => onDelete(item.id)}
            className="text-slate-300 hover:text-red-500 transition-colors"
          >
            <i className="fas fa-trash-alt"></i>
          </button>
        </div>

        <div className="flex flex-wrap items-center gap-3 mb-3">
          <span className={`px-2.5 py-0.5 rounded-full text-xs font-bold uppercase tracking-wider ${config.pill}`}>
            <i className={`fas ${config.icon} mr-1.5`}></i>
            {config.label}
          </span>
          {item.daysRemaining !== null && (
            <span className="text-sm font-medium text-slate-500">
              {item.daysRemaining < 0 
                ? `${Math.abs(item.daysRemaining)} days ago` 
                : `${item.daysRemaining} days left`}
            </span>
          )}
        </div>

        <div className="flex items-center space-x-4 text-sm">
          <div className="flex flex-col">
            <span className="text-slate-400 text-xs uppercase font-semibold">Expiry Date</span>
            <span className={`font-mono font-semibold ${item.status === 'expired' ? 'text-red-600' : 'text-slate-700'}`}>
              {item.expiryDate !== 'YYYY-MM-DD' ? formattedDate : 'Undetected'}
            </span>
          </div>
          <div className="h-8 w-px bg-slate-100"></div>
          <div className="flex flex-col">
            <span className="text-slate-400 text-xs uppercase font-semibold">Label Found</span>
            <span className="italic text-slate-500 truncate max-w-[150px]">"{item.foundText}"</span>
          </div>
        </div>
      </div>

      <div className={`w-1 md:w-2 ${config.bg.replace('50', '500')}`}></div>
    </div>
  );
};

export default ExpiryCard;

import React, { useState, useEffect } from 'react';
import CameraScanner from './components/CameraScanner';
import ImageUploader from './components/ImageUploader';
import ExpiryCard from './components/ExpiryCard';
import { analyzeExpiryImage } from './services/geminiService';
import { ScanMode, ScanResult } from './types';

const App: React.FC = () => {
  const [mode, setMode] = useState<ScanMode>('camera');
  const [results, setResults] = useState<ScanResult[]>([]);
  const [isProcessing, setIsProcessing] = useState(false);
  const [showHistory, setShowHistory] = useState(false);

  // Load results from local storage on mount
  useEffect(() => {
    const saved = localStorage.getItem('freshcheck_results');
    if (saved) {
      try {
        setResults(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to parse history", e);
      }
    }
  }, []);

  // Save results to local storage whenever they change
  useEffect(() => {
    localStorage.setItem('freshcheck_results', JSON.stringify(results));
  }, [results]);

  const handleAnalysis = async (base64: string) => {
    setIsProcessing(true);
    try {
      const analysis = await analyzeExpiryImage(base64);
      const newResult: ScanResult = {
        ...analysis,
        id: crypto.randomUUID(),
        timestamp: Date.now(),
        imageUrl: `data:image/jpeg;base64,${base64}`
      };
      setResults(prev => [newResult, ...prev]);
      setShowHistory(true); // Automatically show history when a scan finishes
    } catch (error) {
      alert("Failed to analyze image. Please try again with a clearer photo.");
      console.error(error);
    } finally {
      setIsProcessing(false);
    }
  };

  const deleteResult = (id: string) => {
    setResults(prev => prev.filter(r => r.id !== id));
  };

  const clearHistory = () => {
    if (confirm("Are you sure you want to clear all scan history?")) {
      setResults([]);
    }
  };

  return (
    <div className="min-h-screen flex flex-col max-w-2xl mx-auto px-4 py-8">
      {/* Header */}
      <header className="flex items-center justify-between mb-8 px-2">
        <div className="flex items-center space-x-3">
          <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white text-xl shadow-lg">
            <i className="fas fa-leaf"></i>
          </div>
          <div>
            <h1 className="text-2xl font-black text-slate-800 tracking-tight leading-none">FreshCheck</h1>
            <p className="text-xs text-slate-500 font-medium">Smart Expiry Assistant</p>
          </div>
        </div>

        <button 
          onClick={() => setShowHistory(!showHistory)}
          className="relative p-2 text-slate-600 hover:text-indigo-600 transition-colors"
        >
          <i className="fas fa-history text-xl"></i>
          {results.length > 0 && (
            <span className="absolute -top-1 -right-1 flex h-5 w-5 items-center justify-center rounded-full bg-red-500 text-[10px] font-bold text-white ring-2 ring-white">
              {results.length}
            </span>
          )}
        </button>
      </header>

      {/* Main Content Area */}
      <main className="flex-1 flex flex-col">
        {!showHistory ? (
          <div className="flex-1 animate-in fade-in slide-in-from-bottom-4 duration-500">
            {/* Mode Toggle */}
            <div className="flex bg-slate-200 p-1 rounded-2xl mb-8 w-max mx-auto">
              <button 
                onClick={() => setMode('camera')}
                className={`px-6 py-2.5 rounded-xl text-sm font-bold transition-all flex items-center space-x-2 ${mode === 'camera' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-600 hover:text-slate-900'}`}
              >
                <i className="fas fa-camera"></i>
                <span>Camera Scan</span>
              </button>
              <button 
                onClick={() => setMode('upload')}
                className={`px-6 py-2.5 rounded-xl text-sm font-bold transition-all flex items-center space-x-2 ${mode === 'upload' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-600 hover:text-slate-900'}`}
              >
                <i className="fas fa-upload"></i>
                <span>Manual Upload</span>
              </button>
            </div>

            {mode === 'camera' ? (
              <CameraScanner onCapture={handleAnalysis} isProcessing={isProcessing} />
            ) : (
              <ImageUploader onUpload={handleAnalysis} isProcessing={isProcessing} />
            )}

            <div className="mt-12 grid grid-cols-2 gap-4">
              <div className="p-4 bg-white rounded-2xl border border-slate-100 shadow-sm flex flex-col items-center text-center">
                <i className="fas fa-bolt text-indigo-500 text-xl mb-2"></i>
                <h4 className="text-sm font-bold text-slate-800">Fast AI</h4>
                <p className="text-[10px] text-slate-500">Real-time detection powered by Gemini</p>
              </div>
              <div className="p-4 bg-white rounded-2xl border border-slate-100 shadow-sm flex flex-col items-center text-center">
                <i className="fas fa-shield-alt text-indigo-500 text-xl mb-2"></i>
                <h4 className="text-sm font-bold text-slate-800">Secure</h4>
                <p className="text-[10px] text-slate-500">Private scanning on your device</p>
              </div>
            </div>
          </div>
        ) : (
          <div className="flex-1 animate-in fade-in slide-in-from-bottom-4 duration-500">
            <div className="flex items-center justify-between mb-6">
              <h2 className="text-xl font-bold text-slate-800 flex items-center">
                <i className="fas fa-list-ul mr-2 text-indigo-600"></i>
                Your Scan Results
              </h2>
              <div className="flex space-x-2">
                {results.length > 0 && (
                  <button 
                    onClick={clearHistory}
                    className="text-xs font-bold text-red-500 hover:text-red-600 px-3 py-1.5 rounded-lg border border-red-100 bg-red-50 transition-colors"
                  >
                    Clear All
                  </button>
                )}
                <button 
                  onClick={() => setShowHistory(false)}
                  className="text-xs font-bold text-indigo-600 hover:text-indigo-700 px-3 py-1.5 rounded-lg border border-indigo-100 bg-indigo-50 transition-colors"
                >
                  New Scan
                </button>
              </div>
            </div>

            {results.length === 0 ? (
              <div className="flex flex-col items-center justify-center py-20 bg-white rounded-3xl border border-dashed border-slate-200">
                <div className="w-16 h-16 bg-slate-50 rounded-full flex items-center justify-center mb-4 text-slate-300">
                  <i className="fas fa-folder-open text-2xl"></i>
                </div>
                <p className="text-slate-400 font-medium">No scan history yet.</p>
                <button 
                  onClick={() => setShowHistory(false)}
                  className="mt-4 text-indigo-600 text-sm font-bold hover:underline"
                >
                  Start your first scan
                </button>
              </div>
            ) : (
              <div className="space-y-4 pb-20">
                {results.map(item => (
                  <ExpiryCard key={item.id} item={item} onDelete={deleteResult} />
                ))}
              </div>
            )}
          </div>
        )}
      </main>

      {/* Floating Action Button for New Scan when in history */}
      {showHistory && results.length > 0 && (
        <button
          onClick={() => setShowHistory(false)}
          className="fixed bottom-8 left-1/2 -translate-x-1/2 bg-indigo-600 text-white px-8 py-4 rounded-full font-bold shadow-2xl hover:bg-indigo-700 hover:scale-105 active:scale-95 transition-all flex items-center space-x-2 z-50"
        >
          <i className="fas fa-plus"></i>
          <span>Scan New Item</span>
        </button>
      )}

      {/* Footer Branding */}
      <footer className="mt-8 pt-6 border-t border-slate-100 text-center">
        <p className="text-slate-400 text-[10px] font-medium uppercase tracking-[0.2em]">
          Powered by Google Gemini 2.5 AI
        </p>
      </footer>
    </div>
  );
};

export default App;

export type Category = 'food' | 'medicine' | 'personal-care' | 'household' | 'other';

export interface ExpiryAnalysis {
  productName: string;
  expiryDate: string; 
  foundText: string;
  confidence: 'high' | 'medium' | 'low';
  isExpired: boolean;
  daysRemaining: number | null;
  status: 'expired' | 'expiring-soon' | 'valid' | 'unknown';
  category: Category;
}

export type AppView = 'dashboard' | 'scan' | 'history';
export type ScanMethod = 'camera' | 'upload' | 'manual';

export interface ScanResult extends ExpiryAnalysis {
  id: string;
  timestamp: number;
  imageUrl?: string;
}

export interface DashboardStats {
  total: number;
  expired: number;
  soon: number;
  safe: number;
}

import { GoogleGenAI, Type } from "@google/genai";
import { ExpiryAnalysis, Category } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const analyzeExpiryImage = async (base64Image: string): Promise<ExpiryAnalysis> => {
  const model = ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: [
      {
        parts: [
          {
            text: `Analyze this product label image.
            1. Identify product name.
            2. Find expiry date.
            3. Categorize the item as one of: food, medicine, personal-care, household, or other.
            4. Return valid JSON.
            Today's date is ${new Date().toISOString().split('T')[0]}.`
          },
          {
            inlineData: {
              mimeType: "image/jpeg",
              data: base64Image
            }
          }
        ]
      }
    ],
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          productName: { type: Type.STRING },
          expiryDate: { type: Type.STRING, description: "YYYY-MM-DD" },
          foundText: { type: Type.STRING },
          confidence: { type: Type.STRING, enum: ["high", "medium", "low"] },
          category: { type: Type.STRING, enum: ["food", "medicine", "personal-care", "household", "other"] }
        },
        required: ["productName", "expiryDate", "foundText", "confidence", "category"]
      }
    }
  });

  const response = await model;
  const data = JSON.parse(response.text || "{}");

  return processAnalysisData(data);
};

export const processAnalysisData = (data: any): ExpiryAnalysis => {
  let isExpired = false;
  let daysRemaining: number | null = null;
  let status: ExpiryAnalysis['status'] = 'unknown';

  try {
    const exp = new Date(data.expiryDate);
    if (!isNaN(exp.getTime())) {
      const today = new Date();
      today.setHours(0, 0, 0, 0);
      const diffTime = exp.getTime() - today.getTime();
      daysRemaining = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

      isExpired = daysRemaining < 0;
      if (isExpired) status = 'expired';
      else if (daysRemaining <= 7) status = 'expiring-soon';
      else status = 'valid';
    }
  } catch (e) {
    console.error("Date calculation error", e);
  }

  return {
    ...data,
    isExpired,
    daysRemaining,
    status,
    category: (data.category as Category) || 'other'
  };
};

import React, { useState } from 'react';
import { Category, ExpiryAnalysis } from '../types';
import { processAnalysisData } from '../services/geminiService';

interface ManualEntryFormProps {
  onSubmit: (analysis: ExpiryAnalysis) => void;
  onCancel: () => void;
}

const ManualEntryForm: React.FC<ManualEntryFormProps> = ({ onSubmit, onCancel }) => {
