import React from 'react';
import { ScanResult, Category } from '../types';

interface ExpiryCardProps {
  item: ScanResult;
  onDelete: (id: string) => void;
}

const CategoryIcon = ({ category }: { category: Category }) => {
  switch (category) {
    case 'food': return <i className="fas fa-utensils"></i>;
    case 'medicine': return <i className="fas fa-pills"></i>;
    case 'personal-care': return <i className="fas fa-bath"></i>;
    case 'household': return <i className="fas fa-home"></i>;
    default: return <i className="fas fa-box"></i>;
  }
};

const ExpiryCard: React.FC<ExpiryCardProps> = ({ item, onDelete }) => {
  const getStatusConfig = () => {
    switch (item.status) {
      case 'expired': return { ring: 'ring-red-100', text: 'text-red-600', bg: 'bg-red-500', label: 'Expired' };
      case 'expiring-soon': return { ring: 'ring-amber-100', text: 'text-amber-600', bg: 'bg-amber-500', label: 'Soon' };
      default: return { ring: 'ring-emerald-100', text: 'text-emerald-600', bg: 'bg-emerald-500', label: 'Fresh' };
    }
  };

  const config = getStatusConfig();
  const date = new Date(item.expiryDate);
  const isInvalidDate = isNaN(date.getTime());

  return (
    <div className="group relative bg-white rounded-3xl p-4 shadow-sm border border-slate-100 hover:shadow-xl hover:-translate-y-1 transition-all duration-300">
      <div className="flex items-start gap-4">
        <div className={`w-14 h-14 rounded-2xl flex items-center justify-center text-xl shrink-0 ${config.bg} text-white shadow-lg shadow-current/20`}>
          {item.imageUrl ? (
            <img src={item.imageUrl} className="w-full h-full object-cover rounded-2xl" alt="" />
          ) : (
            <CategoryIcon category={item.category} />
          )}
        </div>

        <div className="flex-1 min-w-0">
          <div className="flex justify-between">
            <h4 className="font-bold text-slate-800 truncate pr-4 leading-tight">{item.productName}</h4>
            <span className={`text-[10px] font-black uppercase tracking-widest ${config.text}`}>
              {config.label}
            </span>
          </div>

          <div className="flex items-center mt-1 space-x-2">
             <span className="text-[10px] bg-slate-100 text-slate-500 px-2 py-0.5 rounded-md font-bold uppercase">
               {item.category}
             </span>
             <span className="text-xs text-slate-400 font-medium">
               {isInvalidDate ? 'Unknown Date' : date.toLocaleDateString()}
             </span>
          </div>

          <div className="mt-3 flex items-end justify-between">
            <div>
              <p className="text-[10px] font-bold text-slate-300 uppercase">Status</p>
              <p className={`text-sm font-bold ${config.text}`}>
                {item.daysRemaining !== null 
                  ? (item.daysRemaining < 0 ? `${Math.abs(item.daysRemaining)}d ago` : `${item.daysRemaining}d left`)
                  : 'Undated'}
              </p>
            </div>
            <button 
              onClick={() => onDelete(item.id)}
              className="w-8 h-8 rounded-full bg-slate-50 text-slate-300 hover:bg-red-50 hover:text-red-500 transition-colors flex items-center justify-center"
            >
              <i className="fas fa-trash-alt text-xs"></i>
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default ExpiryCard;

import React, { useState, useEffect, useMemo } from 'react';
import CameraScanner from './components/CameraScanner';
import ImageUploader from './components/ImageUploader';
import ManualEntryForm from './components/ManualEntryForm';
import ExpiryCard from './components/ExpiryCard';
import { analyzeExpiryImage } from './services/geminiService';
import { AppView, ScanMethod, ScanResult, Category, DashboardStats } from './types';

const App: React.FC = () => {
  const [view, setView] = useState<AppView>('dashboard');
  const [method, setMethod] = useState<ScanMethod>('camera');
  const [results, setResults] = useState<ScanResult[]>([]);
  const [isProcessing, setIsProcessing] = useState(false);
  const [activeFilter, setActiveFilter] = useState<Category | 'all'>('all');

  useEffect(() => {
    const saved = localStorage.getItem('freshcheck_v2_results');
    if (saved) setResults(JSON.parse(saved));
  }, []);

  useEffect(() => {
    localStorage.setItem('freshcheck_v2_results', JSON.stringify(results));
  }, [results]);

  const stats: DashboardStats = useMemo(() => {
    return results.reduce((acc, curr) => {
      acc.total++;
      if (curr.status === 'expired') acc.expired++;
      else if (curr.status === 'expiring-soon') acc.soon++;
      else acc.safe++;
      return acc;
    }, { total: 0, expired: 0, soon: 0, safe: 0 });
  }, [results]);

  const filteredResults = useMemo(() => {
    return results.filter(r => activeFilter === 'all' || r.category === activeFilter);
  }, [results, activeFilter]);

  const handleScan = async (base64: string) => {
    setIsProcessing(true);
    try {
      const analysis = await analyzeExpiryImage(base64);
      const newResult: ScanResult = {
        ...analysis,
        id: crypto.randomUUID(),
        timestamp: Date.now(),
        imageUrl: `data:image/jpeg;base64,${base64}`
      };
      setResults(prev => [newResult, ...prev]);
      setView('history');
    } catch (e) {
      alert("Analysis failed. Try again.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleManualAdd = (analysis: any) => {
    const newResult: ScanResult = {
      ...analysis,
      id: crypto.randomUUID(),
      timestamp: Date.now()
    };
    setResults(prev => [newResult, ...prev]);
    setView('history');
  };

  const renderDashboard = () => (
    <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className="grid grid-cols-2 gap-4">
        <div className="col-span-2 bg-gradient-to-br from-indigo-600 to-violet-700 p-6 rounded-[2.5rem] text-white shadow-xl shadow-indigo-200">
          <p className="text-indigo-100 text-sm font-semibold opacity-80">Inventory Status</p>
          <h2 className="text-3xl font-black mt-1">{stats.total} <span className="text-lg font-medium opacity-60">Items tracked</span></h2>
          <div className="mt-6 flex space-x-4">
            <button onClick={() => setView('scan')} className="bg-white/20 hover:bg-white/30 backdrop-blur-md px-4 py-2 rounded-xl text-xs font-bold transition-all">
              <i className="fas fa-plus mr-2"></i>Add Item
            </button>
          </div>
        </div>

        <div className="bg-white p-5 rounded-[2rem] shadow-sm border border-slate-50">
          <div className="w-10 h-10 bg-red-100 text-red-600 rounded-2xl flex items-center justify-center mb-3">
            <i className="fas fa-exclamation-circle"></i>
          </div>
          <p className="text-2xl font-black text-slate-800">{stats.expired}</p>
          <p className="text-xs font-bold text-slate-400 uppercase tracking-tighter">Expired</p>
        </div>

        <div className="bg-white p-5 rounded-[2rem] shadow-sm border border-slate-50">
          <div className="w-10 h-10 bg-amber-100 text-amber-600 rounded-2xl flex items-center justify-center mb-3">
            <i className="fas fa-hourglass-half"></i>
          </div>
          <p className="text-2xl font-black text-slate-800">{stats.soon}</p>
          <p className="text-xs font-bold text-slate-400 uppercase tracking-tighter">Expiring Soon</p>
        </div>
      </div>

      <div className="bg-white rounded-[2rem] p-6 shadow-sm border border-slate-50">
        <h3 className="font-bold text-slate-800 mb-4">Categories</h3>
        <div className="grid grid-cols-2 gap-3">
          {['food', 'medicine', 'personal-care', 'household'].map(cat => {
            const count = results.filter(r => r.category === cat).length;
            return (
              <div key={cat} onClick={() => { setActiveFilter(cat as Category); setView('history'); }} className="p-3 bg-slate-50 rounded-2xl border border-transparent hover:border-indigo-100 hover:bg-white cursor-pointer transition-all">
                <p className="text-[10px] font-black uppercase text-slate-400 tracking-wider mb-1">{cat}</p>
                <p className="font-bold text-slate-700">{count} items</p>
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );

  const renderScan = () => (
    <div className="space-y-6 animate-in fade-in zoom-in-95 duration-300 pb-24">
      <div className="flex bg-slate-100 p-1 rounded-2xl max-w-xs mx-auto mb-4">
        {(['camera', 'upload', 'manual'] as ScanMethod[]).map(m => (
          <button
            key={m}
            onClick={() => setMethod(m)}
            className={`flex-1 py-2 text-[10px] font-black uppercase tracking-widest rounded-xl transition-all ${method === m ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-400'}`}
          >
            {m}
          </button>
        ))}
      </div>

      {method === 'camera' && <CameraScanner onCapture={handleScan} isProcessing={isProcessing} />}
      {method === 'upload' && <ImageUploader onUpload={handleScan} isProcessing={isProcessing} />}
      {method === 'manual' && <ManualEntryForm onSubmit={handleManualAdd} onCancel={() => setView('dashboard')} />}
    </div>
  );

  const renderHistory = () => (
    <div className="space-y-4 animate-in fade-in slide-in-from-right-4 duration-300 pb-24">
      <div className="sticky top-0 bg-slate-50/80 backdrop-blur-md py-4 z-10 flex items-center space-x-2 overflow-x-auto no-scrollbar">
        <button 
          onClick={() => setActiveFilter('all')}
          className={`shrink-0 px-4 py-2 rounded-full text-xs font-bold border transition-all ${activeFilter === 'all' ? 'bg-indigo-600 border-indigo-600 text-white' : 'bg-white border-slate-200 text-slate-500'}`}
        >
          All Items
        </button>
        {['food', 'medicine', 'personal-care', 'household'].map(cat => (
          <button 
            key={cat}
            onClick={() => setActiveFilter(cat as Category)}
            className={`shrink-0 px-4 py-2 rounded-full text-xs font-bold border transition-all ${activeFilter === cat ? 'bg-indigo-600 border-indigo-600 text-white' : 'bg-white border-slate-200 text-slate-500'}`}
          >
            {cat.charAt(0).toUpperCase() + cat.slice(1)}
          </button>
        ))}
      </div>

      {filteredResults.length === 0 ? (
        <div className="py-20 text-center space-y-4">
          <div className="w-20 h-20 bg-slate-100 rounded-full flex items-center justify-center mx-auto text-slate-300 text-3xl">
            <i className="fas fa-ghost"></i>
          </div>
          <p className="text-slate-400 font-bold">Nothing found here</p>
          <button onClick={() => setView('scan')} className="text-indigo-600 text-sm font-black uppercase tracking-widest">Add something</button>
        </div>
      ) : (
        <div className="grid grid-cols-1 gap-4">
          {filteredResults.map(item => (
            <ExpiryCard key={item.id} item={item} onDelete={(id) => setResults(prev => prev.filter(r => r.id !== id))} />
          ))}
        </div>
      )}
    </div>
  );

  return (
    <div className="min-h-screen bg-slate-50 font-sans text-slate-900 pb-20 overflow-x-hidden">
      <div className="max-w-md mx-auto px-6 py-8">
        {/* Top Header */}
        <div className="flex justify-between items-center mb-10">
          <div>
            <h1 className="text-2xl font-black text-slate-900 tracking-tight leading-none flex items-center">
              FreshCheck
              <div className="ml-2 w-2 h-2 rounded-full bg-emerald-500"></div>
            </h1>
            <p className="text-[10px] font-black text-indigo-500 uppercase tracking-widest mt-1">Version 2.0 Dashboard</p>
          </div>
          <div className="w-10 h-10 rounded-2xl bg-white shadow-sm flex items-center justify-center text-slate-400 border border-slate-100">
            <i className="fas fa-bell"></i>
          </div>
        </div>

        {/* View Switcher Content */}
        {view === 'dashboard' && renderDashboard()}
        {view === 'scan' && renderScan()}
        {view === 'history' && renderHistory()}

        {/* Floating Navigation Bar */}
        <nav className="fixed bottom-6 left-6 right-6 max-w-sm mx-auto bg-slate-900/90 backdrop-blur-xl rounded-[2.5rem] p-2 flex justify-between items-center shadow-2xl z-50">
          <button 
            onClick={() => setView('dashboard')}
            className={`flex-1 flex flex-col items-center justify-center py-3 rounded-[2rem] transition-all ${view === 'dashboard' ? 'bg-indigo-600 text-white' : 'text-slate-500 hover:text-slate-300'}`}
          >
            <i className="fas fa-th-large text-lg"></i>
          </button>

          <button 
            onClick={() => setView('scan')}
            className={`w-14 h-14 rounded-full flex items-center justify-center shadow-lg -translate-y-4 transition-all ${view === 'scan' ? 'bg-indigo-600 scale-110' : 'bg-slate-700'} text-white`}
          >
            <i className="fas fa-plus text-xl"></i>
          </button>

          <button 
            onClick={() => setView('history')}
            className={`flex-1 flex flex-col items-center justify-center py-3 rounded-[2rem] transition-all ${view === 'history' ? 'bg-indigo-600 text-white' : 'text-slate-500 hover:text-slate-300'}`}
          >
            <i className="fas fa-list text-lg"></i>
          </button>
        </nav>
      </div>

      <style>{`
        .no-scrollbar::-webkit-scrollbar { display: none; }
        .no-scrollbar { -ms-overflow-style: none; scrollbar-width: none; }
      `}</style>
    </div>
  );
};

export default App;

