          { label: 'Expired', count: stats.expired, color: 'text-red-500', bg: 'bg-red-50', icon: 'fa-times-circle' },
          { label: 'Soon', count: stats.soon, color: 'text-amber-500', bg: 'bg-amber-50', icon: 'fa-clock' },
          { label: 'Safe', count: stats.safe, color: 'text-emerald-500', bg: 'bg-emerald-50', icon: 'fa-check-circle' }
        ].map((stat) => (
          <div key={stat.label} className="bg-white p-4 rounded-3xl shadow-sm border border-slate-100 text-center">
            <div className={`w-10 h-10 ${stat.bg} ${stat.color} rounded-2xl flex items-center justify-center mx-auto mb-2`}>
              <i className={`fas ${stat.icon}`}></i>
            </div>
            <p className="text-xl font-black text-slate-800 leading-none">{stat.count}</p>
            <p className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter mt-1">{stat.label}</p>
          </div>
        ))}
      </div>

      {/* Categories Horizontal Scroll */}
      <div>
        <h3 className="text-sm font-black text-slate-800 uppercase tracking-widest mb-4 px-1">Top Categories</h3>
        <div className="flex gap-4 overflow-x-auto no-scrollbar pb-2">
          {['food', 'medicine', 'personal-care', 'household'].map(cat => {
            const count = results.filter(r => r.category === cat).length;
            const icons: Record<string, string> = { food: 'fa-hamburger', medicine: 'fa-capsules', 'personal-care': 'fa-spa', household: 'fa-couch' };
            return (
              <div 
                key={cat} 
                onClick={() => { setActiveFilter(cat as Category); setView('history'); }} 
                className="shrink-0 w-32 p-4 bg-white rounded-[2rem] border border-slate-100 hover:border-indigo-200 hover:shadow-md cursor-pointer transition-all"
              >
                <div className="w-8 h-8 bg-slate-50 text-indigo-600 rounded-xl flex items-center justify-center mb-3">
                  <i className={`fas ${icons[cat]}`}></i>
                </div>
                <p className="text-[10px] font-black uppercase text-slate-400 tracking-wider mb-1">{cat}</p>
                <p className="font-bold text-slate-700 text-sm">{count} items</p>
              </div>
            );
          })}
        </div>
      </div>

      {/* Recent Activity */}
      {recentItems.length > 0 && (
        <div className="animate-in fade-in slide-in-from-bottom-6 duration-700">
          <div className="flex justify-between items-center mb-4 px-1">
            <h3 className="text-sm font-black text-slate-800 uppercase tracking-widest">Recent Activity</h3>
            <button onClick={() => setView('history')} className="text-xs font-bold text-indigo-600">View All</button>
          </div>
          <div className="space-y-3">
            {recentItems.map(item => (
              <div key={item.id} className="flex items-center gap-4 bg-white p-3 rounded-2xl border border-slate-50 shadow-sm">
                 <div className="w-12 h-12 bg-slate-100 rounded-xl overflow-hidden shrink-0">
                    {item.imageUrl ? <img src={item.imageUrl} className="w-full h-full object-cover" /> : <div className="w-full h-full flex items-center justify-center text-slate-300"><i className="fas fa-box"></i></div>}
                 </div>
                 <div className="flex-1 min-w-0">
                    <p className="font-bold text-slate-800 truncate text-sm">{item.productName}</p>
                    <p className="text-[10px] text-slate-400 font-medium">Added {new Date(item.timestamp).toLocaleDateString()}</p>
                 </div>
                 <div className={`px-3 py-1 rounded-lg text-[10px] font-black uppercase ${item.status === 'expired' ? 'bg-red-50 text-red-600' : 'bg-emerald-50 text-emerald-600'}`}>
                   {item.status}
                 </div>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );

  const renderScan = () => (
    <div className="space-y-6 animate-in fade-in zoom-in-95 duration-300 pb-32">
      <div className="flex bg-slate-200/50 backdrop-blur-sm p-1.5 rounded-[1.5rem] max-w-xs mx-auto mb-4 border border-white">
        {(['camera', 'upload', 'manual'] as ScanMethod[]).map(m => (
          <button
            key={m}
            onClick={() => setMethod(m)}
            className={`flex-1 py-2.5 text-[10px] font-black uppercase tracking-widest rounded-xl transition-all ${method === m ? 'bg-white text-indigo-600 shadow-md' : 'text-slate-500'}`}
          >
            {m}
          </button>
        ))}
      </div>

      {method === 'camera' && <CameraScanner onCapture={handleScan} isProcessing={isProcessing} />}
      {method === 'upload' && <ImageUploader onUpload={handleScan} isProcessing={isProcessing} />}
      {method === 'manual' && <ManualEntryForm onSubmit={handleManualAdd} onCancel={() => setView('dashboard')} />}
    </div>
  );

  const renderHistory = () => (
    <div className="space-y-6 animate-in fade-in slide-in-from-right-4 duration-300 pb-32">
      {/* Search & Filter Header */}
      <div className="sticky top-0 bg-slate-50/90 backdrop-blur-xl pt-2 pb-4 z-10 space-y-4">
        <div className="relative">
          <i className="fas fa-search absolute left-4 top-1/2 -translate-y-1/2 text-slate-400"></i>
          <input 
            type="text" 
            placeholder="Search items..." 
            className="w-full pl-12 pr-4 py-3.5 bg-white border border-slate-100 rounded-2xl shadow-sm focus:ring-2 focus:ring-indigo-500 outline-none transition-all font-medium text-sm"
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
          />
        </div>

        <div className="flex items-center space-x-2 overflow-x-auto no-scrollbar py-1">
          <button 
            onClick={() => setActiveFilter('all')}
            className={`shrink-0 px-5 py-2.5 rounded-2xl text-[10px] font-black uppercase tracking-widest border transition-all ${activeFilter === 'all' ? 'bg-indigo-600 border-indigo-600 text-white shadow-lg shadow-indigo-200' : 'bg-white border-slate-100 text-slate-400'}`}
          >
            All
          </button>
          {['food', 'medicine', 'personal-care', 'household'].map(cat => (
            <button 
              key={cat}
              onClick={() => setActiveFilter(cat as Category)}
              className={`shrink-0 px-5 py-2.5 rounded-2xl text-[10px] font-black uppercase tracking-widest border transition-all ${activeFilter === cat ? 'bg-indigo-600 border-indigo-600 text-white shadow-lg shadow-indigo-200' : 'bg-white border-slate-100 text-slate-400'}`}
            >
              {cat}
            </button>
          ))}
        </div>
      </div>

      {filteredResults.length === 0 ? (
        <div className="py-20 text-center space-y-6">
          <div className="w-24 h-24 bg-white rounded-full flex items-center justify-center mx-auto text-slate-200 text-4xl shadow-inner">
            <i className="fas fa-box-open"></i>
          </div>
          <div className="space-y-1">
            <p className="text-slate-600 font-black uppercase tracking-widest text-sm">No items found</p>
            <p className="text-slate-400 text-xs font-medium">Try adjusting your search or filters</p>
          </div>
          <button onClick={() => { setSearchQuery(''); setActiveFilter('all'); }} className="text-indigo-600 text-xs font-black uppercase tracking-widest underline decoration-2 underline-offset-4">Reset View</button>
        </div>
      ) : (
        <div className="grid grid-cols-1 gap-4">
          <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] px-1">Matching Items ({filteredResults.length})</p>
          {filteredResults.map(item => (
            <ExpiryCard key={item.id} item={item} onDelete={(id) => setResults(prev => prev.filter(r => r.id !== id))} />
          ))}
        </div>
      )}
    </div>
  );

  return (
    <div className="min-h-screen bg-slate-50 font-sans text-slate-900 overflow-x-hidden selection:bg-indigo-100">
      <div className="max-w-md mx-auto px-6 pt-10">
        {/* Top App Bar */}
        <div className="flex justify-between items-center mb-8">
          <div className="flex items-center gap-3">
            <div className="w-12 h-12 bg-indigo-600 rounded-[1.25rem] flex items-center justify-center text-white text-2xl shadow-xl shadow-indigo-200 rotate-3 transition-transform hover:rotate-0">
              <i className="fas fa-leaf"></i>
            </div>
            <div>
              <h1 className="text-2xl font-black text-slate-900 tracking-tighter leading-none">FreshCheck</h1>
              <div className="flex items-center gap-2 mt-1">
                <span className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse"></span>
                <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Active Monitoring</p>
              </div>
            </div>
          </div>
          <div className="relative group">
            <div className="w-11 h-11 rounded-2xl bg-white shadow-sm flex items-center justify-center text-slate-500 border border-slate-100 transition-all hover:bg-slate-50 hover:border-slate-200 cursor-pointer">
              <i className="fas fa-user-circle text-lg"></i>
            </div>
          </div>
        </div>

        {/* Dynamic Content */}
        {view === 'dashboard' && renderDashboard()}
        {view === 'scan' && renderScan()}
        {view === 'history' && renderHistory()}

        {/* Modern Floating Bottom Nav */}
        <div className="fixed bottom-0 left-0 right-0 px-6 pb-8 pt-10 pointer-events-none z-50">
          <div className="max-w-md mx-auto bg-slate-900/95 backdrop-blur-2xl rounded-[2.5rem] p-2.5 flex justify-between items-center shadow-[0_20px_50px_rgba(0,0,0,0.3)] pointer-events-auto border border-white/10">
            <button 
              onClick={() => setView('dashboard')}
              className={`flex-1 flex flex-col items-center justify-center py-4 rounded-[2rem] transition-all duration-300 ${view === 'dashboard' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:text-slate-300'}`}
            >
              <i className="fas fa-th-large text-xl"></i>
              <span className="text-[8px] font-black uppercase mt-1 opacity-60">Home</span>
            </button>

            <button 
              onClick={() => setView('scan')}
              className={`w-16 h-16 rounded-full flex items-center justify-center shadow-2xl -translate-y-8 transition-all duration-500 ${view === 'scan' ? 'bg-indigo-600 rotate-90 scale-110 shadow-indigo-500/40' : 'bg-slate-800 hover:bg-slate-700'} text-white border-4 border-slate-900`}
            >
              <i className="fas fa-plus text-2xl"></i>
            </button>

            <button 
              onClick={() => setView('history')}
              className={`flex-1 flex flex-col items-center justify-center py-4 rounded-[2rem] transition-all duration-300 ${view === 'history' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:text-slate-300'}`}
            >
              <i className="fas fa-inventory text-xl"></i>
              <span className="text-[8px] font-black uppercase mt-1 opacity-60">Items</span>
            </button>
          </div>
        </div>
      </div>

      <style>{`
        .no-scrollbar::-webkit-scrollbar { display: none; }
        .no-scrollbar { -ms-overflow-style: none; scrollbar-width: none; }
        @keyframes slideInUp {
          from { transform: translateY(20px); opacity: 0; }
          to { transform: translateY(0); opacity: 1; }
        }
        .animate-up { animation: slideInUp 0.6s cubic-bezier(0.16, 1, 0.3, 1) forwards; }
      `}</style>
    </div>
  );
};

export default App;

import React from 'react';
import { ScanResult, Category } from '../types';

interface ExpiryCardProps {
  item: ScanResult;
  onDelete: (id: string) => void;
}

const CategoryIcon = ({ category }: { category: Category }) => {
  switch (category) {
    case 'food': return <i className="fas fa-hamburger"></i>;
    case 'medicine': return <i className="fas fa-capsules"></i>;
    case 'personal-care': return <i className="fas fa-spa"></i>;
    case 'household': return <i className="fas fa-couch"></i>;
    default: return <i className="fas fa-box"></i>;
  }
};

const ExpiryCard: React.FC<ExpiryCardProps> = ({ item, onDelete }) => {
  const getStatusConfig = () => {
    switch (item.status) {
      case 'expired': return { dot: 'bg-red-500', text: 'text-red-600', bg: 'bg-red-50', label: 'Expired' };
      case 'expiring-soon': return { dot: 'bg-amber-500', text: 'text-amber-600', bg: 'bg-amber-50', label: 'Expiring' };
      default: return { dot: 'bg-emerald-500', text: 'text-emerald-600', bg: 'bg-emerald-50', label: 'Fresh' };
    }
  };

  const config = getStatusConfig();
  const date = new Date(item.expiryDate);
  const isInvalidDate = isNaN(date.getTime());

  return (
    <div className="group relative bg-white rounded-[2.5rem] p-5 shadow-sm border border-slate-100 hover:shadow-xl hover:shadow-indigo-500/5 hover:-translate-y-0.5 transition-all duration-300">
      <div className="flex items-center gap-5">
        <div className="relative shrink-0">
          <div className="w-16 h-16 rounded-[1.5rem] flex items-center justify-center text-xl bg-slate-50 overflow-hidden border border-slate-50 group-hover:border-indigo-100 transition-colors shadow-inner">
            {item.imageUrl ? (
              <img src={item.imageUrl} className="w-full h-full object-cover" alt="" />
            ) : (
              <div className="text-indigo-400">
                <CategoryIcon category={item.category} />
              </div>
            )}
          </div>
          <div className={`absolute -bottom-1 -right-1 w-4 h-4 rounded-full border-2 border-white ${config.dot}`}></div>
        </div>

        <div className="flex-1 min-w-0">
          <div className="flex justify-between items-start">
            <h4 className="font-black text-slate-800 truncate pr-4 text-base tracking-tight">{item.productName}</h4>
          </div>

          <div className="flex items-center mt-0.5 space-x-2">
             <span className="text-[9px] bg-slate-100 text-slate-500 px-2 py-0.5 rounded-md font-black uppercase tracking-widest">
               {item.category}
             </span>
             <span className="text-[10px] text-slate-400 font-bold">
               {isInvalidDate ? 'No Date' : date.toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' })}
             </span>
          </div>

          <div className="mt-3 flex items-center justify-between">
            <div className="flex items-center gap-2">
               <div className={`px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-wider ${config.bg} ${config.text}`}>
                 {item.daysRemaining !== null 
                    ? (item.daysRemaining < 0 ? `${Math.abs(item.daysRemaining)}d ago` : `${item.daysRemaining}d left`)
                    : 'Undated'}
               </div>
            </div>

            <button 
              onClick={() => onDelete(item.id)}
              className="w-9 h-9 rounded-2xl bg-slate-50 text-slate-300 hover:bg-red-50 hover:text-red-500 transition-all flex items-center justify-center"
            >
              <i className="fas fa-trash text-xs"></i>
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default ExpiryCard;
